_FALLBACK_THRESHOLD = int(os.getenv("TOK_FALLBACK_THRESHOLD", "3"))

class RuntimeSession:
    def record_fallback_event(self) -> None:
        self._consecutive_fallback_count += 1
        if self._consecutive_fallback_count >= _FALLBACK_THRESHOLD and not self._baseline_only:
            self._baseline_only = True
            logger.warning("tok_fallback_activated: session degraded to baseline after %d consecutive fallback events", self._consecutive_fallback_count)
